 938 /// Attempts to optimize the induction variable exit values for users in the
 939 /// early exit block.
 940 static VPValue *optimizeEarlyExitInductionUser(VPlan &Plan,
 941                                                VPTypeAnalysis &TypeInfo,
 942                                                VPBlockBase *PredVPBB,
 943                                                VPValue *Op,
 944                                                PredicatedScalarEvolution &PSE) {
 945   VPValue *Incoming, *Mask;
 946   if (!match(Op, m_ExtractLane(m_FirstActiveLane(m_VPValue(Mask)),
 947                                m_VPValue(Incoming))))
 948     return nullptr;
 949 
 950   auto *WideIV = getOptimizableIVOf(Incoming, PSE);
 951   if (!WideIV)
 952     return nullptr;
 953 
 954   auto *WideIntOrFp = dyn_cast<VPWidenIntOrFpInductionRecipe>(WideIV);
 955   if (WideIntOrFp && WideIntOrFp->getTruncInst())
 956     return nullptr;
 957 
 958   // Calculate the final index.
 959   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
 960   auto *CanonicalIV = LoopRegion->getCanonicalIV();
 961   Type *CanonicalIVType = LoopRegion->getCanonicalIVType();
 962   VPBuilder B(cast<VPBasicBlock>(PredVPBB));
 963 
 964   DebugLoc DL = cast<VPInstruction>(Op)->getDebugLoc();
 965   VPValue *FirstActiveLane =
 966       B.createNaryOp(VPInstruction::FirstActiveLane, Mask, DL);
 967   Type *FirstActiveLaneType = TypeInfo.inferScalarType(FirstActiveLane);
 968   FirstActiveLane = B.createScalarZExtOrTrunc(FirstActiveLane, CanonicalIVType,
 969                                               FirstActiveLaneType, DL);
 970   VPValue *EndValue = B.createAdd(CanonicalIV, FirstActiveLane, DL);
 971 
 972   // `getOptimizableIVOf()` always returns the pre-incremented IV, so if it
 973   // changed it means the exit is using the incremented value, so we need to
 974   // add the step.
 975   if (Incoming != WideIV) {
 976     VPValue *One = Plan.getConstantInt(CanonicalIVType, 1);
 977     EndValue = B.createAdd(EndValue, One, DL);
 978   }
 979 
 980   if (!WideIntOrFp || !WideIntOrFp->isCanonical()) {
 981     const InductionDescriptor &ID = WideIV->getInductionDescriptor();
 982     VPIRValue *Start = WideIV->getStartValue();
 983     VPValue *Step = WideIV->getStepValue();
 984     EndValue = B.createDerivedIV(
 985         ID.getKind(), dyn_cast_or_null<FPMathOperator>(ID.getInductionBinOp()),
 986         Start, EndValue, Step);
 987   }
 988 
 989   return EndValue;
 990 }
