 992 /// Attempts to optimize the induction variable exit values for users in the
 993 /// exit block coming from the latch in the original scalar loop.
 994 static VPValue *optimizeLatchExitInductionUser(
 995     VPlan &Plan, VPTypeAnalysis &TypeInfo, VPBlockBase *PredVPBB, VPValue *Op,
 996     DenseMap<VPValue *, VPValue *> &EndValues, PredicatedScalarEvolution &PSE) {
 997   VPValue *Incoming;
 998   VPWidenInductionRecipe *WideIV = nullptr;
 999   if (match(Op, m_ExitingIVValue(m_VPValue(), m_VPValue(Incoming)))) {
1000     WideIV = getOptimizableIVOf(Op->getDefiningRecipe()->getOperand(0), PSE);
1001     assert(WideIV && "must have an optimizable IV");
1002   } else if (match(Op, m_ExtractLastLaneOfLastPart(m_VPValue(Incoming)))) {
1003     WideIV = getOptimizableIVOf(Incoming, PSE);
1004   }
1005 
1006   if (!WideIV)
1007     return nullptr;
1008 
1009   VPValue *EndValue = EndValues.lookup(WideIV);
1010   assert(EndValue && "end value must have been pre-computed");
1011 
1012   // `getOptimizableIVOf()` always returns the pre-incremented IV, so if it
1013   // changed it means the exit is using the incremented value, so we don't
1014   // need to subtract the step.
1015   if (Incoming != WideIV)
1016     return EndValue;
1017 
1018   // Otherwise, subtract the step from the EndValue.
1019   VPBuilder B(cast<VPBasicBlock>(PredVPBB)->getTerminator());
1020   VPValue *Step = WideIV->getStepValue();
1021   Type *ScalarTy = TypeInfo.inferScalarType(WideIV);
1022   if (ScalarTy->isIntegerTy())
1023     return B.createSub(EndValue, Step, DebugLoc::getUnknown(), "ind.escape");
1024   if (ScalarTy->isPointerTy()) {
1025     Type *StepTy = TypeInfo.inferScalarType(Step);
1026     auto *Zero = Plan.getConstantInt(StepTy, 0);
1027     return B.createPtrAdd(EndValue, B.createSub(Zero, Step),
1028                           DebugLoc::getUnknown(), "ind.escape");
1029   }
1030   if (ScalarTy->isFloatingPointTy()) {
1031     const auto &ID = WideIV->getInductionDescriptor();
1032     return B.createNaryOp(
1033         ID.getInductionBinOp()->getOpcode() == Instruction::FAdd
1034             ? Instruction::FSub
1035             : Instruction::FAdd,
1036         {EndValue, Step}, {ID.getInductionBinOp()->getFastMathFlags()});
1037   }
1038   llvm_unreachable("all possible induction types must be handled");
1039   return nullptr;
1040 }
