542       applyFlags(*I);
543     return Res;
544   }
545 
546   switch (getOpcode()) {
547   case VPInstruction::Not: {
548     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
549     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
550     return Builder.CreateNot(A, Name);
