566     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
567     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
568     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
