1663 void VPIRPhi::execute(VPTransformState &State) {
1664   PHINode *Phi = &getIRPhi();
1665   for (const auto &[Idx, Op] : enumerate(operands())) {
1666     VPValue *ExitValue = Op;
1667     auto Lane = vputils::isSingleScalar(ExitValue)
1668                     ? VPLane::getFirstLane()
1669                     : VPLane::getLastLaneForVF(State.VF);
1670     VPBlockBase *Pred = getParent()->getPredecessors()[Idx];
1671     auto *PredVPBB = Pred->getExitingBasicBlock();
1672     BasicBlock *PredBB = State.CFG.VPBB2IRBB[PredVPBB];
1673     // Set insertion point in PredBB in case an extract needs to be generated.
1674     // TODO: Model extracts explicitly.
1675     State.Builder.SetInsertPoint(PredBB, PredBB->getFirstNonPHIIt());
1676     Value *V = State.get(ExitValue, VPLane(Lane));
1677     // If there is no existing block for PredBB in the phi, add a new incoming
1678     // value. Otherwise update the existing incoming value for PredBB.
1679     if (Phi->getBasicBlockIndex(PredBB) == -1)
1680       Phi->addIncoming(V, PredBB);
1681     else
1682       Phi->setIncomingValueForBlock(PredBB, V);
1683   }
1684 
1685   // Advance the insert point after the wrapped IR instruction. This allows
1686   // interleaving VPIRInstructions and other recipes.
1687   State.Builder.SetInsertPoint(Phi->getParent(), std::next(Phi->getIterator()));
1688 }
