1882 /// Compute the cost for the intrinsic \p ID with \p Operands, produced by \p R.
1883 static InstructionCost getCostForIntrinsics(Intrinsic::ID ID,
1884                                             ArrayRef<const VPValue *> Operands,
1885                                             const VPRecipeWithIRFlags &R,
1886                                             ElementCount VF,
1887                                             VPCostContext &Ctx) {
1888   // Some backends analyze intrinsic arguments to determine cost. Use the
1889   // underlying value for the operand if it has one. Otherwise try to use the
1890   // operand of the underlying call instruction, if there is one. Otherwise
1891   // clear Arguments.
1892   // TODO: Rework TTI interface to be independent of concrete IR values.
1893   SmallVector<const Value *> Arguments;
1894   for (const auto &[Idx, Op] : enumerate(Operands)) {
1895     auto *V = Op->getUnderlyingValue();
1896     if (!V) {
1897       if (auto *UI = dyn_cast_or_null<CallBase>(R.getUnderlyingValue())) {
1898         Arguments.push_back(UI->getArgOperand(Idx));
1899         continue;
1900       }
1901       Arguments.clear();
1902       break;
1903     }
1904     Arguments.push_back(V);
1905   }
1906 
1907   Type *ScalarRetTy = Ctx.Types.inferScalarType(&R);
1908   Type *RetTy = VF.isVector() ? toVectorizedTy(ScalarRetTy, VF) : ScalarRetTy;
1909   SmallVector<Type *> ParamTys;
1910   for (const VPValue *Op : Operands) {
1911     ParamTys.push_back(VF.isVector()
1912                            ? toVectorTy(Ctx.Types.inferScalarType(Op), VF)
1913                            : Ctx.Types.inferScalarType(Op));
1914   }
1915 
1916   // TODO: Rework TTI interface to avoid reliance on underlying IntrinsicInst.
1917   FastMathFlags FMF =
1918       R.hasFastMathFlags() ? R.getFastMathFlags() : FastMathFlags();
1919   IntrinsicCostAttributes CostAttrs(
1920       ID, RetTy, Arguments, ParamTys, FMF,
1921       dyn_cast_or_null<IntrinsicInst>(R.getUnderlyingValue()),
1922       InstructionCost::getInvalid(), &Ctx.TLI);
1923   return Ctx.TTI.getIntrinsicInstrCost(CostAttrs, Ctx.CostKind);
1924 }
