1926 InstructionCost VPWidenIntrinsicRecipe::computeCost(ElementCount VF,
1927                                                     VPCostContext &Ctx) const {
1928   SmallVector<const VPValue *> ArgOps(operands());
1929   return getCostForIntrinsics(VectorIntrinsicID, ArgOps, *this, VF, Ctx);
