1513   if (auto *Phi = dyn_cast<VPPhi>(Def)) {
1514     if (Phi->getNumOperands() == 1)
1515       Phi->replaceAllUsesWith(Phi->getOperand(0));
1516     return;
1517   }
1518 
1519   VPIRValue *IRV;
1520   if (Def->getNumOperands() == 1 &&
1521       match(Def, m_ComputeReductionResult(m_VPIRValue(IRV))))
1522     return Def->replaceAllUsesWith(IRV);
1523 
1524   // Some simplifications can only be applied after unrolling. Perform them
1525   // below.
1526   if (!Plan->isUnrolled())
1527     return;
1528 
1529   // After unrolling, extract-lane may be used to extract values from multiple
1530   // scalar sources. Only simplify when extracting from a single scalar source.
1531   VPValue *LaneToExtract;
1532   if (match(Def, m_ExtractLane(m_VPValue(LaneToExtract), m_VPValue(A)))) {
1533     // Simplify extract-lane(%lane_num, %scalar_val) -> %scalar_val.
1534     if (vputils::isSingleScalar(A))
1535       return Def->replaceAllUsesWith(A);
1536 
1537     // Simplify extract-lane with single source to extract-element.
1538     Def->replaceAllUsesWith(Builder.createNaryOp(
1539         Instruction::ExtractElement, {A, LaneToExtract}, Def->getDebugLoc()));
1540     return;
1541   }
1542 
1543   // Hoist an invariant increment Y of a phi X, by having X start at Y.
1544   if (match(Def, m_c_Add(m_VPValue(X), m_VPValue(Y))) && isa<VPIRValue>(Y) &&
1545       isa<VPPhi>(X)) {
1546     auto *Phi = cast<VPPhi>(X);
1547     if (Phi->getOperand(1) != Def && match(Phi->getOperand(0), m_ZeroInt()) &&
1548         Phi->getSingleUser() == Def) {
1549       Phi->setOperand(0, Y);
1550       Def->replaceAllUsesWith(Phi);
1551       return;
1552     }
1553   }
1554 
1555   // Simplify unrolled VectorPointer without offset, or with zero offset, to
1556   // just the pointer operand.
1557   if (auto *VPR = dyn_cast<VPVectorPointerRecipe>(Def))
1558     if (!VPR->getOffset() || match(VPR->getOffset(), m_ZeroInt()))
1559       return VPR->replaceAllUsesWith(VPR->getOperand(0));
1560 
1561   // VPScalarIVSteps after unrolling can be replaced by their start value, if
1562   // the start index is zero and only the first lane 0 is demanded.
1563   if (auto *Steps = dyn_cast<VPScalarIVStepsRecipe>(Def)) {
1564     if (!Steps->getStartIndex() && vputils::onlyFirstLaneUsed(Steps)) {
1565       Steps->replaceAllUsesWith(Steps->getOperand(0));
1566       return;
1567     }
1568   }
1569   // Simplify redundant ReductionStartVector recipes after unrolling.
1570   VPValue *StartV;
1571   if (match(Def, m_VPInstruction<VPInstruction::ReductionStartVector>(
1572                      m_VPValue(StartV), m_VPValue(), m_VPValue()))) {
1573     Def->replaceUsesWithIf(StartV, [](const VPUser &U, unsigned Idx) {
1574       auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&U);
1575       return PhiR && PhiR->isInLoop();
1576     });
1577     return;
1578   }
1579 
1580   if (match(Def, m_ExtractLastLane(m_Broadcast(m_VPValue(A))))) {
1581     Def->replaceAllUsesWith(A);
1582     return;
1583   }
1584 
1585   if (match(Def, m_ExtractLastLane(m_VPValue(A))) &&
1586       ((isa<VPInstruction>(A) && vputils::isSingleScalar(A)) ||
1587        (isa<VPReplicateRecipe>(A) &&
1588         cast<VPReplicateRecipe>(A)->isSingleScalar())) &&
1589       all_of(A->users(),
1590              [Def, A](VPUser *U) { return U->usesScalars(A) || Def == U; })) {
1591     return Def->replaceAllUsesWith(A);
1592   }
1593 
1594   if (Plan->getUF() == 1 && match(Def, m_ExtractLastPart(m_VPValue(A))))
1595     return Def->replaceAllUsesWith(A);
1596 }
