1609 static void narrowToSingleScalarRecipes(VPlan &Plan) {
1610   if (Plan.hasScalarVFOnly())
1611     return;
1612 
1613   // Try to narrow wide and replicating recipes to single scalar recipes,
1614   // based on VPlan analysis. Only process blocks in the loop region for now,
1615   // without traversing into nested regions, as recipes in replicate regions
1616   // cannot be converted yet.
1617   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
1618            vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()))) {
1619     for (VPRecipeBase &R : make_early_inc_range(reverse(*VPBB))) {
1620       if (!isa<VPWidenRecipe, VPWidenGEPRecipe, VPReplicateRecipe,
1621                VPWidenStoreRecipe>(&R))
1622         continue;
1623       auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
1624       if (RepR && (RepR->isSingleScalar() || RepR->isPredicated()))
1625         continue;
1626 
1627       // Convert an unmasked scatter with an uniform address into
1628       // extract-last-lane + scalar store.
1629       // TODO: Add a profitability check comparing the cost of a scatter vs.
1630       // extract + scalar store.
1631       auto *WidenStoreR = dyn_cast<VPWidenStoreRecipe>(&R);
1632       if (WidenStoreR && vputils::isSingleScalar(WidenStoreR->getAddr()) &&
1633           !WidenStoreR->isConsecutive()) {
1634         assert(!WidenStoreR->isReverse() &&
1635                "Not consecutive memory recipes shouldn't be reversed");
1636         VPValue *Mask = WidenStoreR->getMask();
1637 
1638         // Only convert the scatter to a scalar store if it is unmasked.
1639         // TODO: Support converting scatter masked by the header mask to scalar
1640         // store.
1641         if (Mask)
1642           continue;
1643 
1644         auto *Extract = new VPInstruction(VPInstruction::ExtractLastLane,
1645                                           {WidenStoreR->getOperand(1)});
1646         Extract->insertBefore(WidenStoreR);
1647 
1648         // TODO: Sink the scalar store recipe to middle block if possible.
1649         auto *ScalarStore = new VPReplicateRecipe(
1650             &WidenStoreR->getIngredient(), {Extract, WidenStoreR->getAddr()},
1651             true /*IsSingleScalar*/, nullptr /*Mask*/, {},
1652             *WidenStoreR /*Metadata*/);
1653         ScalarStore->insertBefore(WidenStoreR);
1654         WidenStoreR->eraseFromParent();
1655         continue;
1656       }
1657 
1658       auto *RepOrWidenR = dyn_cast<VPRecipeWithIRFlags>(&R);
1659       if (RepR && isa<StoreInst>(RepR->getUnderlyingInstr()) &&
1660           vputils::isSingleScalar(RepR->getOperand(1))) {
1661         auto *Clone = new VPReplicateRecipe(
1662             RepOrWidenR->getUnderlyingInstr(), RepOrWidenR->operands(),
1663             true /*IsSingleScalar*/, nullptr /*Mask*/, *RepR /*Flags*/,
1664             *RepR /*Metadata*/, RepR->getDebugLoc());
1665         Clone->insertBefore(RepOrWidenR);
1666         VPBuilder Builder(Clone);
1667         VPValue *ExtractOp = Clone->getOperand(0);
1668         if (vputils::isUniformAcrossVFsAndUFs(RepR->getOperand(1)))
1669           ExtractOp =
1670               Builder.createNaryOp(VPInstruction::ExtractLastPart, ExtractOp);
1671         ExtractOp =
1672             Builder.createNaryOp(VPInstruction::ExtractLastLane, ExtractOp);
1673         Clone->setOperand(0, ExtractOp);
1674         RepR->eraseFromParent();
1675         continue;
1676       }
1677 
1678       // Skip recipes that aren't single scalars.
1679       if (!RepOrWidenR || !vputils::isSingleScalar(RepOrWidenR))
1680         continue;
1681 
1682       // Skip recipes for which conversion to single-scalar does introduce
1683       // additional broadcasts. No extra broadcasts are needed, if either only
1684       // the scalars of the recipe are used, or at least one of the operands
1685       // would require a broadcast. In the latter case, the single-scalar may
1686       // need to be broadcasted, but another broadcast is removed.
1687       if (!all_of(RepOrWidenR->users(),
1688                   [RepOrWidenR](const VPUser *U) {
1689                     if (auto *VPI = dyn_cast<VPInstruction>(U)) {
1690                       unsigned Opcode = VPI->getOpcode();
1691                       if (Opcode == VPInstruction::ExtractLastLane ||
1692                           Opcode == VPInstruction::ExtractLastPart ||
1693                           Opcode == VPInstruction::ExtractPenultimateElement)
1694                         return true;
1695                     }
1696 
1697                     return U->usesScalars(RepOrWidenR);
1698                   }) &&
1699           none_of(RepOrWidenR->operands(), [RepOrWidenR](VPValue *Op) {
1700             if (Op->getSingleUser() != RepOrWidenR)
1701               return false;
1702             // Non-constant live-ins require broadcasts, while constants do not
1703             // need explicit broadcasts.
1704             auto *IRV = dyn_cast<VPIRValue>(Op);
1705             bool LiveInNeedsBroadcast = IRV && !isa<Constant>(IRV->getValue());
1706             auto *OpR = dyn_cast<VPReplicateRecipe>(Op);
1707             return LiveInNeedsBroadcast || (OpR && OpR->isSingleScalar());
1708           }))
1709         continue;
1710 
1711       auto *Clone = new VPReplicateRecipe(
1712           RepOrWidenR->getUnderlyingInstr(), RepOrWidenR->operands(),
1713           true /*IsSingleScalar*/, nullptr, *RepOrWidenR);
1714       Clone->insertBefore(RepOrWidenR);
1715       RepOrWidenR->replaceAllUsesWith(Clone);
1716       if (isDeadRecipe(*RepOrWidenR))
1717         RepOrWidenR->eraseFromParent();
1718     }
1719   }
1720 }
