5280 /// the induction recipe is not canonical, creates a VPDerivedIVRecipe to
5281 /// compute the end value of the induction.
5282 static VPValue *tryToComputeEndValueForInduction(VPWidenInductionRecipe *WideIV,
5283                                                  VPBuilder &VectorPHBuilder,
5284                                                  VPTypeAnalysis &TypeInfo,
5285                                                  VPValue *VectorTC) {
5286   auto *WideIntOrFp = dyn_cast<VPWidenIntOrFpInductionRecipe>(WideIV);
5287   // Truncated wide inductions resume from the last lane of their vector value
5288   // in the last vector iteration which is handled elsewhere.
5289   if (WideIntOrFp && WideIntOrFp->getTruncInst())
5290     return nullptr;
5291 
5292   VPIRValue *Start = WideIV->getStartValue();
5293   VPValue *Step = WideIV->getStepValue();
5294   const InductionDescriptor &ID = WideIV->getInductionDescriptor();
5295   VPValue *EndValue = VectorTC;
5296   if (!WideIntOrFp || !WideIntOrFp->isCanonical()) {
5297     EndValue = VectorPHBuilder.createDerivedIV(
5298         ID.getKind(), dyn_cast_or_null<FPMathOperator>(ID.getInductionBinOp()),
5299         Start, VectorTC, Step);
5300   }
5301 
5302   // EndValue is derived from the vector trip count (which has the same type as
5303   // the widest induction) and thus may be wider than the induction here.
5304   Type *ScalarTypeOfWideIV = TypeInfo.inferScalarType(WideIV);
5305   if (ScalarTypeOfWideIV != TypeInfo.inferScalarType(EndValue)) {
5306     EndValue = VectorPHBuilder.createScalarCast(Instruction::Trunc, EndValue,
5307                                                 ScalarTypeOfWideIV,
5308                                                 WideIV->getDebugLoc());
5309   }
5310 
5311   return EndValue;
5312 }
