5364 void VPlanTransforms::addExitUsersForFirstOrderRecurrences(VPlan &Plan,
5365                                                            VFRange &Range) {
5366   VPRegionBlock *VectorRegion = Plan.getVectorLoopRegion();
5367   auto *ScalarPHVPBB = Plan.getScalarPreheader();
5368   auto *MiddleVPBB = Plan.getMiddleBlock();
5369   VPBuilder ScalarPHBuilder(ScalarPHVPBB);
5370   VPBuilder MiddleBuilder(MiddleVPBB, MiddleVPBB->getFirstNonPhi());
5371 
5372   auto IsScalableOne = [](ElementCount VF) -> bool {
5373     return VF == ElementCount::getScalable(1);
5374   };
5375 
5376   for (auto &HeaderPhi : VectorRegion->getEntryBasicBlock()->phis()) {
5377     auto *FOR = dyn_cast<VPFirstOrderRecurrencePHIRecipe>(&HeaderPhi);
5378     if (!FOR)
5379       continue;
5380 
5381     assert(VectorRegion->getSingleSuccessor() == Plan.getMiddleBlock() &&
5382            "Cannot handle loops with uncountable early exits");
5383 
5384     // This is the second phase of vectorizing first-order recurrences, creating
5385     // extract for users outside the loop. An overview of the transformation is
5386     // described below. Suppose we have the following loop with some use after
5387     // the loop of the last a[i-1],
5388     //
5389     //   for (int i = 0; i < n; ++i) {
5390     //     t = a[i - 1];
5391     //     b[i] = a[i] - t;
5392     //   }
5393     //   use t;
5394     //
5395     // There is a first-order recurrence on "a". For this loop, the shorthand
5396     // scalar IR looks like:
5397     //
5398     //   scalar.ph:
5399     //     s.init = a[-1]
5400     //     br scalar.body
5401     //
5402     //   scalar.body:
5403     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5404     //     s1 = phi [s.init, scalar.ph], [s2, scalar.body]
5405     //     s2 = a[i]
5406     //     b[i] = s2 - s1
5407     //     br cond, scalar.body, exit.block
5408     //
5409     //   exit.block:
5410     //     use = lcssa.phi [s1, scalar.body]
5411     //
5412     // In this example, s1 is a recurrence because it's value depends on the
5413     // previous iteration. In the first phase of vectorization, we created a
5414     // VPFirstOrderRecurrencePHIRecipe v1 for s1. Now we create the extracts
5415     // for users in the scalar preheader and exit block.
5416     //
5417     //   vector.ph:
5418     //     v_init = vector(..., ..., ..., a[-1])
5419     //     br vector.body
5420     //
5421     //   vector.body
5422     //     i = phi [0, vector.ph], [i+4, vector.body]
5423     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
5424     //     v2 = a[i, i+1, i+2, i+3]
5425     //     b[i] = v2 - v1
5426     //     // Next, third phase will introduce v1' = splice(v1(3), v2(0, 1, 2))
5427     //     b[i, i+1, i+2, i+3] = v2 - v1
5428     //     br cond, vector.body, middle.block
5429     //
5430     //   middle.block:
5431     //     vector.recur.extract.for.phi = v2(2)
5432     //     vector.recur.extract = v2(3)
5433     //     br cond, scalar.ph, exit.block
5434     //
5435     //   scalar.ph:
5436     //     scalar.recur.init = phi [vector.recur.extract, middle.block],
5437     //                             [s.init, otherwise]
5438     //     br scalar.body
5439     //
5440     //   scalar.body:
5441     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5442     //     s1 = phi [scalar.recur.init, scalar.ph], [s2, scalar.body]
5443     //     s2 = a[i]
5444     //     b[i] = s2 - s1
5445     //     br cond, scalar.body, exit.block
5446     //
5447     //   exit.block:
5448     //     lo = lcssa.phi [s1, scalar.body],
5449     //                    [vector.recur.extract.for.phi, middle.block]
5450     //
5451     // Now update VPIRInstructions modeling LCSSA phis in the exit block.
5452     // Extract the penultimate value of the recurrence and use it as operand for
5453     // the VPIRInstruction modeling the phi.
5454     for (VPRecipeBase &R : make_early_inc_range(
5455              make_range(MiddleVPBB->getFirstNonPhi(), MiddleVPBB->end()))) {
5456       if (!match(&R, m_ExtractLastLaneOfLastPart(m_Specific(FOR))))
5457         continue;
5458 
5459       // For VF vscale x 1, if vscale = 1, we are unable to extract the
5460       // penultimate value of the recurrence. Instead we rely on the existing
5461       // extract of the last element from the result of
5462       // VPInstruction::FirstOrderRecurrenceSplice.
5463       // TODO: Consider vscale_range info and UF.
5464       if (LoopVectorizationPlanner::getDecisionAndClampRange(IsScalableOne,
5465                                                              Range))
5466         return;
5467       VPValue *PenultimateElement = MiddleBuilder.createNaryOp(
5468           VPInstruction::ExtractPenultimateElement, FOR->getBackedgeValue(), {},
5469           "vector.recur.extract.for.phi");
5470       cast<VPInstruction>(&R)->replaceAllUsesWith(PenultimateElement);
5471     }
5472   }
