1560 
1561   // VPScalarIVSteps after unrolling can be replaced by their start value, if
1562   // the start index is zero and only the first lane 0 is demanded.
1563   if (auto *Steps = dyn_cast<VPScalarIVStepsRecipe>(Def)) {
1564     if (!Steps->getStartIndex() && vputils::onlyFirstLaneUsed(Steps)) {
1565       Steps->replaceAllUsesWith(Steps->getOperand(0));
1566       return;
1567     }
1568   }
1569   // Simplify redundant ReductionStartVector recipes after unrolling.
1570   VPValue *StartV;
1571   if (match(Def, m_VPInstruction<VPInstruction::ReductionStartVector>(
1572                      m_VPValue(StartV), m_VPValue(), m_VPValue()))) {
1573     Def->replaceUsesWithIf(StartV, [](const VPUser &U, unsigned Idx) {
1574       auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&U);
1575       return PhiR && PhiR->isInLoop();
1576     });
1577     return;
1578   }
1579 
1580   if (match(Def, m_ExtractLastLane(m_Broadcast(m_VPValue(A))))) {
1581     Def->replaceAllUsesWith(A);
1582     return;
1583   }
1584 
1585   if (match(Def, m_ExtractLastLane(m_VPValue(A))) &&
1586       ((isa<VPInstruction>(A) && vputils::isSingleScalar(A)) ||
1587        (isa<VPReplicateRecipe>(A) &&
1588         cast<VPReplicateRecipe>(A)->isSingleScalar())) &&
1589       all_of(A->users(),
1590              [Def, A](VPUser *U) { return U->usesScalars(A) || Def == U; })) {
1591     return Def->replaceAllUsesWith(A);
1592   }
1593 
1594   if (Plan->getUF() == 1 && match(Def, m_ExtractLastPart(m_VPValue(A))))
1595     return Def->replaceAllUsesWith(A);
