1348 bool VPInstruction::usesFirstLaneOnly(const VPValue *Op) const {
1349   assert(is_contained(operands(), Op) && "Op must be an operand of the recipe");
1350   if (Instruction::isBinaryOp(getOpcode()) || Instruction::isCast(getOpcode()))
1351     return vputils::onlyFirstLaneUsed(this);
1352 
1353   switch (getOpcode()) {
1354   default:
1355     return false;
1356   case Instruction::ExtractElement:
1357     return Op == getOperand(1);
1358   case Instruction::PHI:
1359     return true;
1360   case Instruction::FCmp:
1361   case Instruction::ICmp:
1362   case Instruction::Select:
1363   case Instruction::Or:
1364   case Instruction::Freeze:
1365   case VPInstruction::Not:
1366     // TODO: Cover additional opcodes.
1367     return vputils::onlyFirstLaneUsed(this);
1368   case VPInstruction::ActiveLaneMask:
1369   case VPInstruction::ExplicitVectorLength:
1370   case VPInstruction::CalculateTripCountMinusVF:
1371   case VPInstruction::CanonicalIVIncrementForPart:
1372   case VPInstruction::BranchOnCount:
1373   case VPInstruction::BranchOnCond:
1374   case VPInstruction::Broadcast:
1375   case VPInstruction::ReductionStartVector:
1376     return true;
1377   case VPInstruction::BuildStructVector:
1378   case VPInstruction::BuildVector:
1379     // Before replicating by VF, Build(Struct)Vector uses all lanes of the
1380     // operand, after replicating its operands only the first lane is used.
1381     // Before replicating, it will have only a single operand.
1382     return getNumOperands() > 1;
1383   case VPInstruction::PtrAdd:
1384     return Op == getOperand(0) || vputils::onlyFirstLaneUsed(this);
1385   case VPInstruction::WidePtrAdd:
1386     // WidePtrAdd supports scalar and vector base addresses.
1387     return false;
1388   case VPInstruction::ComputeAnyOfResult:
1389     return Op == getOperand(0) || Op == getOperand(1);
1390   case VPInstruction::ExitingIVValue:
1391   case VPInstruction::ExtractLane:
1392     return Op == getOperand(0);
1393   };
1394   llvm_unreachable("switch should return");
