5475 void VPlanTransforms::optimizeFindIVReductions(VPlan &Plan,
5476                                                PredicatedScalarEvolution &PSE,
5477                                                Loop &L) {
5478   ScalarEvolution &SE = *PSE.getSE();
5479   VPRegionBlock *VectorLoopRegion = Plan.getVectorLoopRegion();
5480 
5481   // Helper lambda to check if the IV range excludes the sentinel value.
5482   auto CheckSentinel = [&SE](const SCEV *IVSCEV, bool UseMax,
5483                              bool Signed) -> std::optional<APInt> {
5484     unsigned BW = IVSCEV->getType()->getScalarSizeInBits();
5485     APInt Sentinel =
5486         UseMax
5487             ? (Signed ? APInt::getSignedMinValue(BW) : APInt::getMinValue(BW))
5488             : (Signed ? APInt::getSignedMaxValue(BW) : APInt::getMaxValue(BW));
5489 
5490     ConstantRange IVRange =
5491         Signed ? SE.getSignedRange(IVSCEV) : SE.getUnsignedRange(IVSCEV);
5492     if (!IVRange.contains(Sentinel))
5493       return Sentinel;
5494     return std::nullopt;
5495   };
5496 
5497   for (VPRecipeBase &Phi :
5498        make_early_inc_range(VectorLoopRegion->getEntryBasicBlock()->phis())) {
5499     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&Phi);
5500     if (!PhiR || !RecurrenceDescriptor::isFindLastRecurrenceKind(
5501                      PhiR->getRecurrenceKind()))
5502       continue;
5503 
5504     // Get the IV from the backedge value of the reduction phi.
5505     // The backedge value should be a select between the phi and the IV.
5506     VPValue *BackedgeVal = PhiR->getBackedgeValue();
5507     VPValue *TrueVal, *FalseVal;
5508     if (!match(BackedgeVal,
5509                m_Select(m_VPValue(), m_VPValue(TrueVal), m_VPValue(FalseVal))))
5510       continue;
5511 
5512     // The non-phi operand of the select is the IV.
5513     assert(is_contained(BackedgeVal->getDefiningRecipe()->operands(), PhiR));
5514     VPValue *IV = TrueVal == PhiR ? FalseVal : TrueVal;
5515 
5516     const SCEV *IVSCEV = vputils::getSCEVExprForVPValue(IV, PSE, &L);
5517     const SCEV *Step;
5518     if (!match(IVSCEV, m_scev_AffineAddRec(m_SCEV(), m_SCEV(Step))))
5519       continue;
5520 
5521     // Determine direction from SCEV step.
5522     if (!SE.isKnownNonZero(Step))
5523       continue;
5524 
5525     // Positive step means we need UMax/SMax to find the last IV value, and
5526     // UMin/SMin otherwise.
5527     bool UseMax = SE.isKnownPositive(Step);
5528     bool UseSigned = true;
5529     std::optional<APInt> SentinelVal =
5530         CheckSentinel(IVSCEV, UseMax, /*IsSigned=*/true);
5531     if (!SentinelVal) {
5532       SentinelVal = CheckSentinel(IVSCEV, UseMax, /*IsSigned=*/false);
5533       if (!SentinelVal)
5534         continue;
5535       UseSigned = false;
5536     }
5537 
5538     auto *RdxResult = cast<VPInstruction>(vputils::findRecipe(
5539         BackedgeVal,
5540         match_fn(m_VPInstruction<VPInstruction::ComputeReductionResult>())));
5541 
5542     // Create the reduction result in the middle block using sentinel directly.
5543     RecurKind MinMaxKind =
5544         UseMax ? (UseSigned ? RecurKind::SMax : RecurKind::UMax)
5545                : (UseSigned ? RecurKind::SMin : RecurKind::UMin);
5546     VPIRFlags Flags(MinMaxKind, /*IsOrdered=*/false, /*IsInLoop=*/false,
5547                     FastMathFlags());
5548     VPValue *Sentinel = Plan.getConstantInt(*SentinelVal);
5549     DebugLoc ExitDL = RdxResult->getDebugLoc();
5550     VPBuilder MiddleBuilder(RdxResult);
5551     VPValue *ReducedIV =
5552         MiddleBuilder.createNaryOp(VPInstruction::ComputeReductionResult,
5553                                    RdxResult->getOperand(0), Flags, ExitDL);
5554     auto *Cmp =
5555         MiddleBuilder.createICmp(CmpInst::ICMP_NE, ReducedIV, Sentinel, ExitDL);
5556     VPInstruction *NewRdxResult = MiddleBuilder.createSelect(
5557         Cmp, ReducedIV, PhiR->getStartValue(), ExitDL);
5558     RdxResult->replaceAllUsesWith(NewRdxResult);
5559     RdxResult->eraseFromParent();
5560 
5561     auto *NewPhiR = new VPReductionPHIRecipe(
5562         cast<PHINode>(PhiR->getUnderlyingInstr()), RecurKind::FindIV, *Sentinel,
5563         *BackedgeVal, RdxUnordered{1}, PhiR->hasUsesOutsideReductionChain());
5564     NewPhiR->insertBefore(PhiR);
5565     PhiR->replaceAllUsesWith(NewPhiR);
5566     PhiR->eraseFromParent();
5567   }
