1967 void VPHistogramRecipe::execute(VPTransformState &State) {
1968   IRBuilderBase &Builder = State.Builder;
1969 
1970   Value *Address = State.get(getOperand(0));
1971   Value *IncAmt = State.get(getOperand(1), /*IsScalar=*/true);
1972   VectorType *VTy = cast<VectorType>(Address->getType());
1973 
1974   // The histogram intrinsic requires a mask even if the recipe doesn't;
1975   // if the mask operand was omitted then all lanes should be executed and
1976   // we just need to synthesize an all-true mask.
1977   Value *Mask = nullptr;
1978   if (VPValue *VPMask = getMask())
1979     Mask = State.get(VPMask);
1980   else
1981     Mask =
1982         Builder.CreateVectorSplat(VTy->getElementCount(), Builder.getInt1(1));
1983 
1984   // If this is a subtract, we want to invert the increment amount. We may
1985   // add a separate intrinsic in future, but for now we'll try this.
1986   if (Opcode == Instruction::Sub)
1987     IncAmt = Builder.CreateNeg(IncAmt);
1988   else
1989     assert(Opcode == Instruction::Add && "only add or sub supported for now");
1990 
1991   State.Builder.CreateIntrinsic(Intrinsic::experimental_vector_histogram_add,
1992                                 {VTy, IncAmt->getType()},
1993                                 {Address, IncAmt, Mask});
1994 }
1995 
1996 InstructionCost VPHistogramRecipe::computeCost(ElementCount VF,
1997                                                VPCostContext &Ctx) const {
1998   // FIXME: Take the gather and scatter into account as well. For now we're
1999   //        generating the same cost as the fallback path, but we'll likely
2000   //        need to create a new TTI method for determining the cost, including
2001   //        whether we can use base + vec-of-smaller-indices or just
2002   //        vec-of-pointers.
2003   assert(VF.isVector() && "Invalid VF for histogram cost");
2004   Type *AddressTy = Ctx.Types.inferScalarType(getOperand(0));
2005   VPValue *IncAmt = getOperand(1);
2006   Type *IncTy = Ctx.Types.inferScalarType(IncAmt);
2007   VectorType *VTy = VectorType::get(IncTy, VF);
2008 
2009   // Assume that a non-constant update value (or a constant != 1) requires
2010   // a multiply, and add that into the cost.
2011   InstructionCost MulCost =
2012       Ctx.TTI.getArithmeticInstrCost(Instruction::Mul, VTy, Ctx.CostKind);
2013   if (auto *CI = dyn_cast<VPConstantInt>(IncAmt))
2014     if (CI->isOne())
2015       MulCost = TTI::TCC_Free;
2016 
2017   // Find the cost of the histogram operation itself.
2018   Type *PtrTy = VectorType::get(AddressTy, VF);
2019   Type *MaskTy = VectorType::get(Type::getInt1Ty(Ctx.LLVMCtx), VF);
2020   IntrinsicCostAttributes ICA(Intrinsic::experimental_vector_histogram_add,
2021                               Type::getVoidTy(Ctx.LLVMCtx),
2022                               {PtrTy, IncTy, MaskTy});
2023 
2024   // Add the costs together with the add/sub operation.
2025   return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind) + MulCost +
2026          Ctx.TTI.getArithmeticInstrCost(Opcode, VTy, Ctx.CostKind);
2027 }
