2508 void VPScalarIVStepsRecipe::execute(VPTransformState &State) {
2509   // Fast-math-flags propagate from the original induction instruction.
2510   IRBuilder<>::FastMathFlagGuard FMFG(State.Builder);
2511   if (hasFastMathFlags())
2512     State.Builder.setFastMathFlags(getFastMathFlags());
2513 
2514   /// Compute scalar induction steps. \p ScalarIV is the scalar induction
2515   /// variable on which to base the steps, \p Step is the size of the step.
2516 
2517   Value *BaseIV = State.get(getOperand(0), VPLane(0));
2518   Value *Step = State.get(getStepValue(), VPLane(0));
2519   IRBuilderBase &Builder = State.Builder;
2520 
2521   // Ensure step has the same type as that of scalar IV.
2522   Type *BaseIVTy = BaseIV->getType()->getScalarType();
2523   assert(BaseIVTy == Step->getType() && "Types of BaseIV and Step must match!");
2524 
2525   // We build scalar steps for both integer and floating-point induction
2526   // variables. Here, we determine the kind of arithmetic we will perform.
2527   Instruction::BinaryOps AddOp;
2528   Instruction::BinaryOps MulOp;
2529   if (BaseIVTy->isIntegerTy()) {
2530     AddOp = Instruction::Add;
2531     MulOp = Instruction::Mul;
2532   } else {
2533     AddOp = InductionOpcode;
2534     MulOp = Instruction::FMul;
2535   }
2536 
2537   // Determine the number of scalars we need to generate.
2538   bool FirstLaneOnly = vputils::onlyFirstLaneUsed(this);
2539   // Compute the scalar steps and save the results in State.
2540 
2541   unsigned StartLane = 0;
2542   unsigned EndLane = FirstLaneOnly ? 1 : State.VF.getKnownMinValue();
2543   if (State.Lane) {
2544     StartLane = State.Lane->getKnownLane();
2545     EndLane = StartLane + 1;
2546   }
2547   Value *StartIdx0 = getStartIndex() ? State.get(getStartIndex(), true)
2548                                      : Constant::getNullValue(BaseIVTy);
2549 
2550   for (unsigned Lane = StartLane; Lane < EndLane; ++Lane) {
2551     // It is okay if the induction variable type cannot hold the lane number,
2552     // we expect truncation in this case.
2553     Constant *LaneValue =
2554         BaseIVTy->isIntegerTy()
2555             ? ConstantInt::get(BaseIVTy, Lane, /*IsSigned=*/false,
2556                                /*ImplicitTrunc=*/true)
2557             : ConstantFP::get(BaseIVTy, Lane);
2558     Value *StartIdx = Builder.CreateBinOp(AddOp, StartIdx0, LaneValue);
2559     // The step returned by `createStepForVF` is a runtime-evaluated value
2560     // when VF is scalable. Otherwise, it should be folded into a Constant.
2561     assert((State.VF.isScalable() || isa<Constant>(StartIdx)) &&
2562            "Expected StartIdx to be folded to a constant when VF is not "
2563            "scalable");
2564     auto *Mul = Builder.CreateBinOp(MulOp, StartIdx, Step);
2565     auto *Add = Builder.CreateBinOp(AddOp, BaseIV, Mul);
2566     State.set(this, Add, VPLane(Lane));
2567   }
2568 }
