5318   auto *MiddleVPBB = cast<VPBasicBlock>(ScalarPH->getPredecessors()[0]);
5319   VPRegionBlock *VectorRegion = Plan.getVectorLoopRegion();
5320   VPBuilder VectorPHBuilder(
5321       cast<VPBasicBlock>(VectorRegion->getSinglePredecessor()));
5322   VPBuilder MiddleBuilder(MiddleVPBB, MiddleVPBB->getFirstNonPhi());
5323   for (VPRecipeBase &PhiR : Plan.getScalarPreheader()->phis()) {
5324     auto *ResumePhiR = cast<VPPhi>(&PhiR);
5325 
5326     // TODO: Extract final value from induction recipe initially, optimize to
5327     // pre-computed end value together in optimizeInductionExitUsers.
5328     auto *VectorPhiR = cast<VPHeaderPHIRecipe>(ResumePhiR->getOperand(0));
5329     if (auto *WideIVR = dyn_cast<VPWidenInductionRecipe>(VectorPhiR)) {
5330       if (VPValue *EndValue = tryToComputeEndValueForInduction(
5331               WideIVR, VectorPHBuilder, TypeInfo, &Plan.getVectorTripCount())) {
5332         IVEndValues[WideIVR] = EndValue;
5333         ResumePhiR->setOperand(0, EndValue);
5334         ResumePhiR->setName("bc.resume.val");
5335         continue;
5336       }
5337       // TODO: Also handle truncated inductions here. Computing end-values
5338       // separately should be done as VPlan-to-VPlan optimization, after
5339       // legalizing all resume values to use the last lane from the loop.
5340       assert(cast<VPWidenIntOrFpInductionRecipe>(VectorPhiR)->getTruncInst() &&
5341              "should only skip truncated wide inductions");
5342       continue;
5343     }
5344 
5345     // The backedge value provides the value to resume coming out of a loop,
5346     // which for FORs is a vector whose last element needs to be extracted. The
5347     // start value provides the value if the loop is bypassed.
5348     bool IsFOR = isa<VPFirstOrderRecurrencePHIRecipe>(VectorPhiR);
5349     auto *ResumeFromVectorLoop = VectorPhiR->getBackedgeValue();
5350     assert(VectorRegion->getSingleSuccessor() == Plan.getMiddleBlock() &&
5351            "Cannot handle loops with uncountable early exits");
5352     if (IsFOR) {
5353       auto *ExtractPart = MiddleBuilder.createNaryOp(
5354           VPInstruction::ExtractLastPart, ResumeFromVectorLoop);
5355       ResumeFromVectorLoop = MiddleBuilder.createNaryOp(
5356           VPInstruction::ExtractLastLane, ExtractPart, DebugLoc::getUnknown(),
5357           "vector.recur.extract");
5358     }
5359     ResumePhiR->setName(IsFOR ? "scalar.recur.init" : "bc.merge.rdx");
5360     ResumePhiR->setOperand(0, ResumeFromVectorLoop);
