5572 /// A chain of recipes that form a partial reduction. Matches either
5573 ///   reduction_bin_op (extend (A), accumulator), or
5574 ///   reduction_bin_op (bin_op (extend (A), (extend (B))), accumulator).
5575 struct VPPartialReductionChain {
5576   /// The top-level binary operation that forms the reduction to a scalar
5577   /// after the loop body.
5578   VPWidenRecipe *ReductionBinOp;
5579   /// The extension of each of the inner binary operation's operands.
5580   VPWidenCastRecipe *ExtendA;
5581   VPWidenCastRecipe *ExtendB;
5582   /// The user of the extends that is then reduced.
5583   VPWidenRecipe *BinOp;
5584   unsigned ScaleFactor;
5585 };
5586 
5587 // Helper to transform a partial reduction chain into a partial reduction
5588 // recipe. Returns true if transformation succeeded. Checks profitability and
5589 // clamps VF range.
5590 static bool transformToPartialReduction(const VPPartialReductionChain &Chain,
5591                                         VFRange &Range, VPCostContext &CostCtx,
5592                                         VPlan &Plan) {
5593   VPWidenRecipe *WidenRecipe = Chain.ReductionBinOp;
5594   unsigned ScaleFactor = Chain.ScaleFactor;
5595   assert(WidenRecipe->getNumOperands() == 2 && "Expected binary operation");
5596 
5597   VPValue *BinOp = WidenRecipe->getOperand(0);
5598   VPValue *Accumulator = WidenRecipe->getOperand(1);
5599 
5600   // Swap if needed to ensure Accumulator is the PHI or partial reduction.
5601   if (isa_and_present<VPReductionPHIRecipe, VPReductionRecipe>(BinOp))
5602     std::swap(BinOp, Accumulator);
5603 
5604   // For chained reductions, only transform if accumulator is already a PHI or
5605   // partial reduction. Otherwise, it needs to be transformed first.
5606   auto *AccumRecipe = Accumulator->getDefiningRecipe();
5607   if (!isa_and_present<VPReductionPHIRecipe, VPReductionRecipe>(AccumRecipe))
5608     return false;
5609 
5610   // Check if the partial reduction is profitable for the VF range.
5611   Type *PhiType = CostCtx.Types.inferScalarType(Accumulator);
5612 
5613   // Derive extend info from the stored extends.
5614   auto GetExtInfo = [&CostCtx](VPWidenCastRecipe *Ext)
5615       -> std::pair<Type *, TargetTransformInfo::PartialReductionExtendKind> {
5616     if (!Ext)
5617       return {nullptr, TargetTransformInfo::PR_None};
5618     Type *ExtOpType = CostCtx.Types.inferScalarType(Ext->getOperand(0));
5619     auto ExtKind = TargetTransformInfo::getPartialReductionExtendKind(
5620         static_cast<Instruction::CastOps>(Ext->getOpcode()));
5621     return {ExtOpType, ExtKind};
5622   };
5623   auto ExtInfoA = GetExtInfo(Chain.ExtendA);
5624   auto ExtInfoB = GetExtInfo(Chain.ExtendB);
5625   Type *ExtOpTypeA = ExtInfoA.first;
5626   Type *ExtOpTypeB = ExtInfoB.first;
5627   auto ExtKindA = ExtInfoA.second;
5628   auto ExtKindB = ExtInfoB.second;
5629   // If ExtendB is nullptr but there's a separate BinOp, the second operand
5630   // was a constant that can use the same extend kind as the first.
5631   if (!Chain.ExtendB && Chain.BinOp && Chain.BinOp != Chain.ReductionBinOp) {
5632     // Validate that the constant can be extended to the narrow type.
5633     const APInt *Const = nullptr;
5634     for (VPValue *Op : Chain.BinOp->operands()) {
5635       if (match(Op, m_APInt(Const)))
5636         break;
5637     }
5638     if (!Const || !canConstantBeExtended(Const, ExtOpTypeA, ExtKindA))
5639       return false;
5640     ExtOpTypeB = ExtOpTypeA;
5641     ExtKindB = ExtKindA;
5642   }
5643 
5644   // BinOpc is only set when there's a separate binary op (not when BinOp is
5645   // the reduction itself).
5646   std::optional<unsigned> BinOpc =
5647       (Chain.BinOp && Chain.BinOp != Chain.ReductionBinOp)
5648           ? std::make_optional(Chain.BinOp->getOpcode())
5649           : std::nullopt;
